import java.time.format.DateTimeParseException;

import static org.junit.jupiter.api.Assertions.*;

public class DateSchemaColumn_parseAndAddToColumn_Test {

    // Simple stub for DfColumn to record added objects and count
    private static class StubDfColumn implements DfColumn {
        Object lastAdded;
        int addCount = 0;

        @Override
